def _add_account_operation_submit_arguments(parser: argparse.ArgumentParser) -> None:
    parser.add_argument("--pool-account-id", required=True)
    parser.add_argument("--organization-id", required=True)
    parser.add_argument(
        "--product-id",
        default=None,
        help=(
            "Optional workspace Product/CTA context: product truth, description/media, and "
            "promotion guidance; an explicit audience action is optional. Re-submitting the "
            "same Product is idempotent; changing it is rejected."
        ),
    )
    parser.add_argument("--niche", default=None)
    parser.add_argument("--persona-id", default=None)
    parser.add_argument(
        "--session-conversation-id",
        default=None,
        help=(
            "Work-session conversation (topic/thread) to bind as the account's "
            "workbench; defaults to the CURRENT session from the per-turn runtime context."
        ),
    )
    parser.add_argument("--target-delivery-mode", default=None)
    parser.add_argument(
        "--research-prompt",
        default=None,
        help=(
            "Operator's research directive (free text; may include benchmark accounts). "
            "ONLY pass when the operator explicitly mentioned research direction — "
            "forces research even for established accounts."
        ),
    )
    parser.add_argument(
        "--reference-url",
        default=None,
        help=(
            "Benchmark account URL the operator named for research anchoring. "
            "ONLY pass when explicitly mentioned."
        ),
    )
    parser.add_argument(
        "--preferred-publish-time",
        default=None,
        help=(
            "Preferred daily publish time as 24h HH:MM (e.g. 17:00). Stored on the "
            "operation; the daily routine then schedules posts at this local time. "
            "Pair with --publish-timezone."
        ),
    )
    parser.add_argument(
        "--publish-timezone",
        default=None,
        help="IANA timezone for --preferred-publish-time (e.g. Asia/Shanghai).",
    )
    parser.add_argument("--dry-run", action="store_true")


def _build_account_operation_submit_arguments(args: argparse.Namespace) -> dict[str, Any]:
    return {
        "pool_account_id": args.pool_account_id,
        "organization_id": args.organization_id,
        "product_id": args.product_id,
        "niche": args.niche,
        "persona_id": args.persona_id,
        "session_conversation_id": args.session_conversation_id,
        "target_delivery_mode": args.target_delivery_mode,
        "research_prompt": args.research_prompt,
        "reference_url": args.reference_url,
        "preferred_publish_time": args.preferred_publish_time,
        "preferred_publish_timezone": args.publish_timezone,
    }


