async def _execute_submit(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    arguments = ctx.arguments
    workspace_id = ctx.workspace_id
    api_data_v2 = ctx.api_data_v2
    runtime = cfg.runtime_context if isinstance(cfg.runtime_context, dict) else {}
    # Per-turn patched runtime context: conversation_id == the CURRENT session
    # (topic/thread) — the account's dedicated workbench.
    session_conversation_id = arguments.get("session_conversation_id") or runtime.get(
        "conversation_id"
    )
    source_channel_message_id = runtime.get("source_channel_message_id")
    payload = compact_params(
        {
            "workspace_id": workspace_id,
            "organization_id": arguments.get("organization_id"),
            "pool_account_id": arguments.get("pool_account_id"),
            "persona_id": arguments.get("persona_id"),
            "product_id": arguments.get("product_id"),
            "niche": arguments.get("niche"),
            "session_conversation_id": session_conversation_id,
            "source_channel_message_id": source_channel_message_id,
            "target_delivery_mode": arguments.get("target_delivery_mode"),
            "research_prompt": arguments.get("research_prompt"),
            "reference_url": arguments.get("reference_url"),
            "preferred_publish_time": arguments.get("preferred_publish_time"),
            "preferred_publish_timezone": arguments.get("preferred_publish_timezone"),
        }
    )
    return await api_data_v2(cfg, "POST", "/account-operations", json_body=payload)


async def _execute_submit_batch(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    arguments = ctx.arguments
    runtime = cfg.runtime_context if isinstance(cfg.runtime_context, dict) else {}
    session_conversation_id = arguments.get("session_conversation_id") or runtime.get(
        "conversation_id"
    )
    raw_ids = str(arguments.get("pool_account_ids") or "")
    pool_ids = [part.strip() for part in raw_ids.split(",") if part.strip()]
    payload = compact_params(
        {
            "workspace_id": ctx.workspace_id,
            "organization_id": arguments.get("organization_id"),
            "session_conversation_id": session_conversation_id,
            "source_channel_message_id": runtime.get("source_channel_message_id"),
            "target_delivery_mode": arguments.get("target_delivery_mode"),
            "product_id": arguments.get("product_id"),
            "niche": arguments.get("niche"),
            "research_prompt": arguments.get("research_prompt"),
            "reference_url": arguments.get("reference_url"),
            "preferred_publish_time": arguments.get("preferred_publish_time"),
            "preferred_publish_timezone": arguments.get("preferred_publish_timezone"),
            "accounts": [{"pool_account_id": pid} for pid in pool_ids],
        }
    )
    return await ctx.api_data_v2(cfg, "POST", "/account-operations/batch:submit", json_body=payload)


